(async function init() {
  try {
    window._supabase = createClient(SUPABASE_URL, SUPABASE_KEY);
  } catch(e) {
    document.body.innerHTML = '<div style="padding:40px;font-family:sans-serif;color:#c62828;"><h2>Supabase failed to load</h2><p>Check your internet connection and reload.</p><pre>' + escapeHtml(e.message) + '</pre></div>';
    return;
  }
  window._dbg = (msg) => {
    const bar = document.getElementById('debug-bar');
    bar.style.display = 'block';
    bar.innerHTML += '<div>' + new Date().toISOString().slice(11,19) + ' ' + escapeHtml(msg) + '</div>';
    bar.scrollTop = bar.scrollHeight;
    console.log('[DBG]', msg);
  };
  window._dbg('init started, window.supabase=' + (typeof window.supabase));
  showToast('Loading data...');
  try {
    window._dbg('fetching leads...'); const { data: dbLeads, error: leadsErr } = await window._supabase.from('leads').select('*').order('created_at'); window._dbg('leads result: ' + (leadsErr ? 'ERR:'+JSON.stringify(leadsErr) : (dbLeads ? dbLeads.length + ' rows' : 'null')));
    if (leadsErr) throw leadsErr;

    if (!dbLeads || dbLeads.length === 0) {
      const seedRows = LEADS.map(l => leadToDbRow(l));
      const { data: seeded, error: seedErr } = await window._supabase.from('leads').insert(seedRows).select();
      if (seedErr) throw seedErr;
      allLeads = (seeded || []).map(dbRowToLead);
    } else {
      allLeads = dbLeads.map(dbRowToLead);
    }

    const { data: dbLogs, error: logsErr } = await window._supabase.from('call_logs').select('*').order('created_at');
    if (logsErr) throw logsErr;

    callLog = (dbLogs || []).map(log => {
      const lead = allLeads.find(l => l.id === log.lead_id) || {};
      return {
        ...log,
        company: lead.company || '—',
        contact_name: lead.contact_name || '—',
        contact_title: lead.contact_title || '—',
        follow_up: log.next_action_date,
      };
    });

    // Auto-apply research-based pain points to any lead with fewer than 6
    const leadsNeedingUpdate = allLeads.filter(l => !l.pain_points || l.pain_points.length < 6);
    if (leadsNeedingUpdate.length) {
      for (const lead of leadsNeedingUpdate) {
        const newPoints = inferPainPoints(lead.contact_title || '', lead.industry || '');
        if (newPoints.length) {
          await window._supabase.from('leads').update({ pain_points: newPoints }).eq('id', lead.id);
          lead.pain_points = newPoints;
        }
      }
    }
    initFilters();
    initScriptSelect();
    initToneSelector();
    initLogForm();
    renderLeads();
    updateSidebarStats();
    renderApolloTitleTags();
    updateApiKeyStatuses();
    window._dbg('init complete, allLeads=' + allLeads.length); showToast('Ready'); document.getElementById('debug-bar').style.display='none';
  } catch (err) {
    window._dbg('CATCH: ' + (err.message || JSON.stringify(err)));
    console.error('Init error:', err);
    showToast('Error: ' + (err.message || err));
  }
})();